  ('judicial-f0899a01-moex-00046', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲為計程車司機，駕駛計程車時，因與車內乘客聊天，致超車時，不慎撞擊前方機車，致騎乘機車乙人車 倒地，乙跌倒時臉部正好撞到路邊小灌木，致右眼受傷，眼睛視力從1.2減至0.1，且永久無法恢復該眼視 力。甲之行為應如何論罪？', '["過失傷害罪", "過失傷害致重傷害罪", "過失重傷罪", "重傷罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00047', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '關於傷害罪章之罪，下列敘述何者正確？', '["我國刑法並無過失傷害罪", "聚眾鬥毆致人於死或重傷者，在場助勢之人不構成犯罪", "對於未滿18 歲之人，施以凌虐或以他法足以妨害其身心之健全或發育者，雖未有客觀可見之傷口，亦 構成犯罪", "激於義憤犯傷害罪者，其處罰較普通傷害罪為重"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00048', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '房東甲安裝針孔攝影機，偷拍房客乙與男友性交行為之影片，甲事後告訴乙此事，並威脅乙如不與自己一 同外出約會，將公開該影片，乙拒絕甲之要求，甲遂將影片公開於色情網站。甲不成立下列何罪？', '["公然侮辱罪", "竊錄他人非公開活動罪", "強制未遂罪", "散布猥褻物品罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00049', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關刑法第27章妨害名譽及信用罪的敘述，下列何者錯誤？', '["誹謗是針對具體事實而為陳述", "對於所誹謗之事，只要能證明其為真實者，即使涉及私德無關公共利益，也是不罰", "以散布文字、圖畫犯誹謗罪，為加重誹謗罪", "所謂意圖散布於眾，係指意圖散發或傳布於不特定之多數人而言"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00050', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '下列何者非屬刑法第307條非法搜索罪所定之行為客體？', '["他人之身體", "他人之建築物", "他人之車輛", "他人之隨身物件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00051', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '依實務見解，下列何種情況不成立刑法第321條加重竊盜罪？', '["甲以螺絲起子撬開鎖頭竊取機車", "20歲之甲、19歲之乙及12歲之丙一同竊取財物", "甲在公寓之樓梯間竊取腳踏車", "甲侵入旅館房間竊取旅客財物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00052', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲改造一艘廢棄遠洋漁船，與友人乙、丙，乘船至某海港，上岸持槍劫掠港口商家。關於甲之行為，下列 何者正確？', '["成立加重搶奪罪", "成立加重強盜罪", "成立海盜罪", "成立恐嚇取財罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00053', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '撘高鐵的A下車時，不慎將其皮夾放在座位上，後來為乘客甲拾取，甲未交給警察機關，反而將其內的新 臺幣3,000元花用殆盡，甲的行為如何處置？', '["甲僅屬於民法的不當得利，並無刑法問題", "甲乃意圖為自己不法所有侵占遺失物，應構成刑法第337條犯罪", "甲乃將業務上持有他人之物侵占，應構成刑法第336條第2項犯罪", "甲乃是將自己持有他人之物侵占，應構成刑法第335條犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00054', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '犯詐欺罪而有下列何者情形之一者，處1年以上7年以下有期徒刑，得併科100萬元以下罰金？', '["冒用私人機構名義犯之", "2人以上共同犯之", "以廣播電視、電子通訊、網際網路或其他媒體等傳播工具，對公眾散布而犯之", "以不正方法由收費設備取得他人之物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00055', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-0f9358e7', 'sub-judicial-f0899a01-03', NULL, 'essay', '最高法院為法律審，於最高法院民事庭審理案件期間，當事人於何種情
